<?php
/**
 * TELEPAGE — bin/migrate-tag-slugs.php
 *
 * One-shot maintenance script: consolidate tag rows whose slug was
 * generated by one of the 4 divergent slugify implementations that
 * existed in Telepage before fix #21. See that commit for context.
 *
 * What it does:
 *   1. For every row in `tags`, recomputes the slug canonically
 *      via Str::slugify(name).
 *   2. If the canonical slug == current slug → no-op, skip.
 *   3. If the canonical slug is free (no other tag uses it) → UPDATE
 *      the single row's slug.
 *   4. If the canonical slug collides with another tag → MERGE:
 *      winner chosen by usage_count (higher wins); then source
 *      preference (manual > scanner/ai); then lowest id as tie-break.
 *      Loser rows have their content_tags references re-assigned to
 *      the winner (INSERT OR IGNORE to absorb duplicates), then the
 *      loser row is deleted. Winner's slug is rewritten to canonical.
 *
 * Safety:
 *   - Runs in dry-run mode by default — NOTHING is changed unless
 *     --apply is passed explicitly.
 *   - Before --apply, writes a timestamped backup copy of the DB
 *     file next to the original.
 *   - All writes happen in a single transaction — either the full
 *     migration completes or it rolls back entirely.
 *   - Idempotent: re-running on a migrated DB is a no-op.
 *   - CLI-only: refuses to run via HTTP.
 *
 * Usage:
 *     php bin/migrate-tag-slugs.php            # dry-run, safe
 *     php bin/migrate-tag-slugs.php --apply    # actually rewrite
 *     php bin/migrate-tag-slugs.php --help
 */

declare(strict_types=1);

if (PHP_SAPI !== 'cli') {
    http_response_code(403);
    exit("This script is CLI-only.\n");
}

define('TELEPAGE_ROOT', dirname(__DIR__));

require_once TELEPAGE_ROOT . '/vendor/autoload.php';

// -----------------------------------------------------------------------
// Args
// -----------------------------------------------------------------------

$args  = array_slice($argv, 1);
$apply = in_array('--apply', $args, true);
$help  = in_array('--help', $args, true) || in_array('-h', $args, true);

if ($help) {
    echo "Usage: php bin/migrate-tag-slugs.php [--apply]\n";
    echo "  (no args)  Dry-run — show what would change, touch nothing.\n";
    echo "  --apply    Make a DB backup, then actually execute the merge.\n";
    exit(0);
}

echo "Telepage — tag slug consolidation\n";
echo "Mode: " . ($apply ? 'APPLY (will write)' : 'DRY-RUN (no writes)') . "\n\n";

// -----------------------------------------------------------------------
// Load current tags
// -----------------------------------------------------------------------

$tags = DB::fetchAll('SELECT id, name, slug, source, usage_count FROM tags ORDER BY id');
if (empty($tags)) {
    echo "No tags in DB. Nothing to do.\n";
    exit(0);
}

echo "Loaded " . count($tags) . " tag rows.\n";

// -----------------------------------------------------------------------
// Plan the migration
// -----------------------------------------------------------------------
//
// Two-pass: first compute the canonical slug for every tag, group by
// canonical, decide winners and losers. Then we generate the ordered
// list of operations to apply.
//
// Output of this phase:
//   $plan = [
//     ['op' => 'noop',   'tag' => row]                     → nothing to do
//     ['op' => 'reslug', 'tag' => row, 'new_slug' => …]    → single UPDATE
//     ['op' => 'merge',  'winner' => row, 'losers' => […], 'new_slug' => …]
//   ]

$byCanonical = []; // canonical_slug => [rows]
foreach ($tags as $row) {
    $canonical = Str::slugify($row['name']);
    if ($canonical === '') {
        // Degenerate name (pure punctuation) — keep current slug, skip.
        continue;
    }
    $byCanonical[$canonical][] = $row;
}

/**
 * Returns the "winning" row from a set of rows that collide on a
 * canonical slug. Policy: highest usage_count → then manual source
 * over scanner/ai → then lowest id.
 */
function pickWinner(array $rows): array {
    usort($rows, function ($a, $b) {
        $ua = (int) $a['usage_count'];
        $ub = (int) $b['usage_count'];
        if ($ua !== $ub) return $ub <=> $ua;
        $sa = ($a['source'] === 'manual') ? 0 : 1;
        $sb = ($b['source'] === 'manual') ? 0 : 1;
        if ($sa !== $sb) return $sa <=> $sb;
        return (int) $a['id'] <=> (int) $b['id'];
    });
    return $rows[0];
}

$plan = [];
foreach ($byCanonical as $canonical => $group) {
    if (count($group) === 1) {
        $row = $group[0];
        if ($row['slug'] === $canonical) {
            $plan[] = ['op' => 'noop', 'tag' => $row];
        } else {
            $plan[] = ['op' => 'reslug', 'tag' => $row, 'new_slug' => $canonical];
        }
        continue;
    }
    // Collision — need a merge.
    $winner = pickWinner($group);
    $losers = array_values(array_filter(
        $group,
        fn($r) => (int) $r['id'] !== (int) $winner['id']
    ));
    $plan[] = [
        'op'       => 'merge',
        'winner'   => $winner,
        'losers'   => $losers,
        'new_slug' => $canonical,
    ];
}

// -----------------------------------------------------------------------
// Report the plan
// -----------------------------------------------------------------------

$stats = ['noop' => 0, 'reslug' => 0, 'merge' => 0, 'deleted' => 0];

foreach ($plan as $step) {
    if ($step['op'] === 'noop') {
        $stats['noop']++;
        continue;
    }
    if ($step['op'] === 'reslug') {
        $stats['reslug']++;
        $t = $step['tag'];
        printf(
            "  [reslug] tag#%d '%s': slug '%s' → '%s'\n",
            $t['id'], $t['name'], $t['slug'], $step['new_slug']
        );
        continue;
    }
    if ($step['op'] === 'merge') {
        $stats['merge']++;
        $stats['deleted'] += count($step['losers']);
        $w = $step['winner'];
        printf(
            "  [merge]  winner tag#%d '%s' (slug '%s', usage=%d, source=%s)\n",
            $w['id'], $w['name'], $w['slug'], $w['usage_count'], $w['source']
        );
        foreach ($step['losers'] as $l) {
            printf(
                "           <- loser tag#%d '%s' (slug '%s', usage=%d, source=%s) — will be deleted, FKs reassigned\n",
                $l['id'], $l['name'], $l['slug'], $l['usage_count'], $l['source']
            );
        }
        if ($w['slug'] !== $step['new_slug']) {
            printf(
                "           winner slug will also be rewritten: '%s' → '%s'\n",
                $w['slug'], $step['new_slug']
            );
        }
    }
}

echo "\n";
printf(
    "Plan: %d no-op, %d reslug, %d merge, %d rows to delete.\n",
    $stats['noop'], $stats['reslug'], $stats['merge'], $stats['deleted']
);

if (!$apply) {
    echo "\nDry-run complete. Re-run with --apply to execute.\n";
    exit(0);
}

// -----------------------------------------------------------------------
// Backup
// -----------------------------------------------------------------------

$dbPath = Config::getKey('db_path', TELEPAGE_ROOT . '/data/app.sqlite');
$backupPath = $dbPath . '.backup-' . date('Ymd-His');
if (!copy($dbPath, $backupPath)) {
    fwrite(STDERR, "ERROR: could not create backup at {$backupPath}. Aborting.\n");
    exit(1);
}
echo "Backup written: {$backupPath}\n\n";

// -----------------------------------------------------------------------
// Execute
// -----------------------------------------------------------------------

$pdo = DB::get();
$pdo->beginTransaction();

try {
    foreach ($plan as $step) {
        if ($step['op'] === 'noop') continue;

        if ($step['op'] === 'reslug') {
            DB::query(
                'UPDATE tags SET slug = :slug WHERE id = :id',
                [':slug' => $step['new_slug'], ':id' => $step['tag']['id']]
            );
            continue;
        }

        if ($step['op'] === 'merge') {
            $winnerId = (int) $step['winner']['id'];
            foreach ($step['losers'] as $loser) {
                $loserId = (int) $loser['id'];

                // Re-point content_tags rows from loser to winner.
                // INSERT OR IGNORE handles the case where the same content
                // was already tagged with the winner — the composite PK
                // would otherwise complain.
                DB::query(
                    'INSERT OR IGNORE INTO content_tags (content_id, tag_id)
                     SELECT content_id, :wid FROM content_tags WHERE tag_id = :lid',
                    [':wid' => $winnerId, ':lid' => $loserId]
                );

                // Remove the loser's original rows (CASCADE would also
                // fire on delete of the tag below, but being explicit
                // reads clearer and decouples us from schema changes).
                DB::query(
                    'DELETE FROM content_tags WHERE tag_id = :lid',
                    [':lid' => $loserId]
                );

                // Fold the loser's usage_count into the winner before
                // deleting. Simple sum — approximates the "true" count
                // for the merged tag. A VACUUM + recount could be more
                // accurate but is outside this script's scope.
                DB::query(
                    'UPDATE tags SET usage_count = usage_count + :add WHERE id = :wid',
                    [':add' => (int) $loser['usage_count'], ':wid' => $winnerId]
                );

                DB::query(
                    'DELETE FROM tags WHERE id = :lid',
                    [':lid' => $loserId]
                );
            }

            // Now that all losers are gone, the canonical slug is free.
            // Rewrite the winner's slug (if it differs from canonical).
            if ($step['winner']['slug'] !== $step['new_slug']) {
                DB::query(
                    'UPDATE tags SET slug = :slug WHERE id = :id',
                    [':slug' => $step['new_slug'], ':id' => $winnerId]
                );
            }
        }
    }

    $pdo->commit();
    echo "Migration applied successfully.\n";
    echo "Backup kept at: {$backupPath}\n";
    echo "If anything looks wrong, stop Apache/PHP and:\n";
    echo "  cp {$backupPath} {$dbPath}\n";
} catch (Throwable $e) {
    $pdo->rollBack();
    fwrite(STDERR, "ERROR during migration: " . $e->getMessage() . "\n");
    fwrite(STDERR, "Transaction rolled back. DB is unchanged.\n");
    fwrite(STDERR, "Backup kept at: {$backupPath}\n");
    exit(1);
}
